from __future__ import annotations

from typing import Any

TRADING_STATUS_PRIORITY = {
    "TRADING_ALLOWED": 0,
    "BUY_HALT": 1,
    "SELL_ONLY": 2,
    "FULL_HALT": 3,
}

TRADING_STATUS_LABEL_CN = {
    "TRADING_ALLOWED": "允许交易",
    "BUY_HALT": "禁止买入",
    "SELL_ONLY": "仅允许卖出",
    "FULL_HALT": "全部停止",
}

SELL_ONLY_REASONS = {
    "orders_pending_without_execution",
    "review_required",
    "close_review_pending_sell_handoff",
}

NO_SIGNAL_REASONS = {
    "预处理后无有效信号（pending_after_gate=0）",
    "净额合并后无有效订单（pending_netted=0）",
}


def _normalize_gate_reasons(value: Any) -> list[str]:
    if not value:
        return []
    return [str(item).strip() for item in value if str(item).strip()]


MARKET_GATE_REASON_PREFIXES = (
    "index_ret_pct",
    "market_breadth",
    "intraday_market_",
    "intraday_breadth_",
    "premarket_breadth_",
)
STYLE_GATE_REASONS = {"style_rotation_riskoff", "style_rotation_hard_stop"}
VOLATILITY_GATE_REASON_PREFIXES = ("volatility_",)
LIQUIDITY_GATE_REASON_PREFIXES = ("liquidity_",)
MANUAL_GATE_REASON_PREFIXES = ("manual_",)


def classify_gate_reasons(gate_reasons: list[str] | None) -> dict[str, list[str]]:
    reasons = _normalize_gate_reasons(gate_reasons)
    classified = {
        "market": [],
        "style": [],
        "volatility": [],
        "liquidity": [],
        "manual": [],
        "other": [],
    }
    for reason in reasons:
        if reason in STYLE_GATE_REASONS:
            classified["style"].append(reason)
        elif reason.startswith(MARKET_GATE_REASON_PREFIXES):
            classified["market"].append(reason)
        elif reason.startswith(VOLATILITY_GATE_REASON_PREFIXES):
            classified["volatility"].append(reason)
        elif reason.startswith(LIQUIDITY_GATE_REASON_PREFIXES):
            classified["liquidity"].append(reason)
        elif reason.startswith(MANUAL_GATE_REASON_PREFIXES):
            classified["manual"].append(reason)
        else:
            classified["other"].append(reason)
    return classified


def derive_dimension_state(dimension: str, reasons: list[str]) -> str:
    normalized = _normalize_gate_reasons(reasons)
    if not normalized:
        return "normal"
    if dimension == "style":
        if "style_rotation_hard_stop" in normalized:
            return "halt"
        if "style_rotation_riskoff" in normalized:
            return "risk_off"
        return "active"
    if dimension == "volatility":
        if "volatility_hard_stop" in normalized:
            return "halt"
        if any("unavailable" in reason for reason in normalized):
            return "unavailable"
        return "risk_off"
    if dimension == "liquidity":
        if "liquidity_hard_stop" in normalized:
            return "halt"
        if any("unavailable" in reason for reason in normalized):
            return "unavailable"
        return "risk_off"
    if any(
        reason.startswith(("market_breadth_hard_stop", "premarket_breadth_hard_stop", "intraday_market_halt", "intraday_breadth_halt"))
        or reason.startswith("index_ret_pct")
        for reason in normalized
    ):
        return "halt"
    if any("unavailable" in reason for reason in normalized):
        return "unavailable"
    return "risk_off"


def trading_status_to_cn(status: str) -> str:
    return TRADING_STATUS_LABEL_CN.get(str(status or "").strip().upper(), "未知状态")


def derive_trading_status(
    *,
    state: str,
    mode: str,
    risk_off: bool,
    hard_stop: bool,
    halt_new_buy: bool,
    state_reason: str,
) -> str:
    state_text = str(state or "").strip()
    mode_text = str(mode or "").strip().lower()
    reason_text = str(state_reason or "").strip()
    sell_only_mode = mode_text == "review_required" and reason_text in {"", "review_required"}
    sell_only_reason = reason_text in SELL_ONLY_REASONS

    if hard_stop or state_text in {"risk_halt", "blocked", "no_data"}:
        if state_text == "blocked" and (sell_only_reason or sell_only_mode):
            return "SELL_ONLY"
        return "FULL_HALT"
    if sell_only_reason or sell_only_mode:
        return "SELL_ONLY"
    if halt_new_buy or risk_off or state_text == "risk_off" or mode_text in {"cautious", "observe"}:
        return "BUY_HALT"
    return "TRADING_ALLOWED"


