        status = derive_trading_status(
            state=str(enriched.get("state") or ""),
            mode=str(enriched.get("mode") or ""),
            risk_off=bool(enriched.get("risk_off")),
            hard_stop=bool(enriched.get("hard_stop")),
            halt_new_buy=bool(enriched.get("halt_new_buy")),
            state_reason=reason,
        )
